import { StreamingChatShellScreen } from "@/components/streaming-chat-shell/streaming-chat-shell-screen";

export default function StreamingChatShellPage() {
  return <StreamingChatShellScreen />;
}

import { handleStreamingChatShellRequest } from "@/lib/streaming-chat-shell/runtime";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleStreamingChatShellRequest(request);
}

import { handleStreamingChatShellEventsRequest } from "@/lib/streaming-chat-shell/events";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleStreamingChatShellEventsRequest(request);
}

import { Badge } from "@/components/ui/badge";

import { getStreamingChatShellRuntimeState } from "@/lib/streaming-chat-shell/runtime";

import { StreamingChatShellWorkspace } from "./streaming-chat-shell-workspace";

export function StreamingChatShellScreen() {
  const runtimeState = getStreamingChatShellRuntimeState();

  return (
    <main className="min-h-svh bg-background text-foreground">
      <div className="mx-auto flex w-full max-w-7xl flex-col gap-6 px-4 py-6 md:px-6">
        <header className="grid gap-4 border border-foreground/10 bg-background px-4 py-5 md:grid-cols-[minmax(0,1fr)_auto] md:items-end">
          <div className="space-y-2">
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Demo / Streaming Chat Shell
            </p>
            <h1 className="max-w-3xl font-medium text-2xl tracking-tight">
              A developer-facing chat runtime shell with replayable streaming
              trace
            </h1>
            <p className="max-w-3xl text-muted-foreground text-sm/relaxed">
              This demo shows how one chat session can drive the user-facing
              transcript and a developer-side replay stream at the same time.
            </p>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            <Badge variant="outline">{runtimeState.statusLabel}</Badge>
            <Badge variant="outline">{runtimeState.chatModel}</Badge>
          </div>
        </header>

        <StreamingChatShellWorkspace
          chatModel={runtimeState.chatModel}
          isChatAvailable={runtimeState.isChatAvailable}
          nodeVersion={runtimeState.nodeVersion}
          setupMessage={runtimeState.setupMessage}
          supportedAudiences={runtimeState.supportedAudiences}
        />
      </div>
    </main>
  );
}

"use client";

import { Chat, useChat } from "@ai-sdk/react";
import {
  ArrowClockwiseIcon,
  BroadcastIcon,
  CaretDownIcon,
  RobotIcon,
  StopIcon,
} from "@phosphor-icons/react";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { cn } from "@/lib/utils";
import { DefaultChatTransport, type UIMessage } from "ai";
import { useMemo, useState } from "react";

import type { StreamingAudience } from "@/lib/streaming-chat-shell/contract";
import {
  getReplayPromptEntries,
  useStreamingReplayPrompt,
  type ReplayPromptEntry,
} from "./streaming-replay";

function getTextContent(message: UIMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n");
}

function getAudienceLabel(audience: StreamingAudience) {
  switch (audience) {
    case "buyers":
      return "Buyers";
    case "support":
      return "Support";
    case "engineers":
    default:
      return "Engineers";
  }
}

interface StreamingChatShellWorkspaceProps {
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
  supportedAudiences: string[];
}

interface StreamingTranscriptProps {
  chat: Chat<UIMessage>;
  isChatAvailable: boolean;
  setupMessage: string | null;
}

interface StreamingComposerProps {
  audience: StreamingAudience;
  chat: Chat<UIMessage>;
  chatModel: string;
  isChatAvailable: boolean;
  onAudienceChange: (audience: StreamingAudience) => void;
  supportedAudiences: StreamingAudience[];
}

interface StreamingDeveloperTraceProps {
  audience: StreamingAudience;
  chat: Chat<UIMessage>;
}

interface ReplayPromptCardProps {
  audience: StreamingAudience;
  defaultOpen?: boolean;
  entry: ReplayPromptEntry;
  title: string;
}

function StreamingTranscript({
  chat,
  isChatAvailable,
  setupMessage,
}: StreamingTranscriptProps) {
  const { error, messages } = useChat({ chat });
  const hasMessages = messages.length > 0;

  return (
    <>
      {isChatAvailable ? null : (
        <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
          {setupMessage}
        </div>
      )}

      {error ? (
        <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
          {error.message}
        </div>
      ) : null}

      <Conversation>
        <ConversationContent className="mx-auto flex w-full max-w-3xl flex-1 gap-6 px-4 py-6">
          {hasMessages ? (
            messages.map((message) => {
              const text = getTextContent(message);

              return (
                <Message from={message.role} key={message.id}>
                  <MessageContent
                    className={cn(
                      message.role === "assistant" ? "max-w-3xl" : "max-w-2xl"
                    )}
                  >
                    {text ? (
                      <MessageResponse>{text}</MessageResponse>
                    ) : (
                      <p className="text-muted-foreground text-sm">
                        Waiting for visible output.
                      </p>
                    )}
                  </MessageContent>
                </Message>
              );
            })
          ) : (
            <ConversationEmptyState
              description="Send a prompt, then inspect how the same chat history can be replayed as a developer-side SSE trace."
              icon={<RobotIcon className="size-5" />}
              title="Developer replay shell is ready"
            />
          )}
        </ConversationContent>
        <ConversationScrollButton />
      </Conversation>
    </>
  );
}

function StreamingComposer({
  audience,
  chat,
  chatModel,
  isChatAvailable,
  onAudienceChange,
  supportedAudiences,
}: StreamingComposerProps) {
  const { messages, regenerate, sendMessage, status, stop } = useChat({ chat });
  const hasMessages = messages.length > 0;
  const isBusy = status === "submitted" || status === "streaming";

  async function handleSend(text: string) {
    const trimmedText = text.trim();

    if (!trimmedText) {
      return;
    }

    await sendMessage(
      {
        text: trimmedText,
      },
      {
        body: { audience },
      }
    );
  }

  return (
    <div className="border-foreground/10 border-t px-4 py-4">
      <div className="mx-auto w-full max-w-3xl space-y-3">
        <div className="flex flex-wrap items-center gap-2">
          {supportedAudiences.map((option) => {
            const isActive = option === audience;

            return (
              <Button
                className="h-8 px-3 text-xs"
                key={option}
                onClick={() => onAudienceChange(option)}
                size="sm"
                type="button"
                variant={isActive ? "default" : "outline"}
              >
                {getAudienceLabel(option)}
              </Button>
            );
          })}
        </div>

        <PromptInput onSubmit={({ text }) => handleSend(text)}>
          <PromptInputBody>
            <PromptInputTextarea
              disabled={!isChatAvailable || isBusy}
              placeholder="Send a prompt, then inspect the replay trace on the right."
            />
          </PromptInputBody>
          <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
            <div className="flex flex-wrap items-center gap-2">
              <Badge variant="outline">Custom body</Badge>
              <Badge variant="outline">Shared useChat</Badge>
              <Badge variant="outline">{chatModel}</Badge>
            </div>
            <div className="flex items-center gap-2">
              {isBusy ? (
                <Button
                  onClick={stop}
                  size="sm"
                  type="button"
                  variant="outline"
                >
                  <StopIcon className="size-3.5" />
                  Stop
                </Button>
              ) : null}
              {hasMessages ? (
                <Button
                  onClick={() => regenerate({ body: { audience } })}
                  size="sm"
                  type="button"
                  variant="outline"
                >
                  <ArrowClockwiseIcon className="size-3.5" />
                  Retry
                </Button>
              ) : null}
              <PromptInputSubmit disabled={!isChatAvailable} status={status} />
            </div>
          </PromptInputFooter>
        </PromptInput>
      </div>
    </div>
  );
}

function ReplayPromptCard({
  audience,
  defaultOpen = false,
  entry,
  title,
}: ReplayPromptCardProps) {
  const { error, events, isReplayable, status, traceText, replayPrompt } =
    useStreamingReplayPrompt(audience, entry);

  return (
    <Collapsible className="border border-foreground/10" defaultOpen={defaultOpen}>
      <CollapsibleTrigger className="flex w-full items-center justify-between gap-4 px-3 py-3 text-left">
        <div className="space-y-1">
          <p className="font-medium text-sm">{title}</p>
          <p className="text-muted-foreground text-xs/relaxed line-clamp-3">
            {entry.promptText}
          </p>
        </div>
        <CaretDownIcon className="size-4 text-muted-foreground transition-transform group-data-[state=open]:rotate-180" />
      </CollapsibleTrigger>

      <CollapsibleContent className="space-y-4 border-foreground/10 border-t px-3 py-3">
        <div className="flex flex-wrap items-center gap-2">
          <Badge variant="outline">{getAudienceLabel(audience)}</Badge>
          <Badge variant="outline">{entry.replayMessages.length} messages</Badge>
          {events.length > 0 ? (
            <Badge variant="outline">{events.length} events</Badge>
          ) : null}
        </div>

        <div className="space-y-2">
          <Button
            disabled={!isReplayable || status === "loading"}
            onClick={replayPrompt}
            size="sm"
            type="button"
            variant="outline"
          >
            <BroadcastIcon className="size-3.5" />
            Replay prompt turn
          </Button>
          <p className="text-muted-foreground text-xs/relaxed">
            Correlated user prompt: "{entry.promptText}"
          </p>
        </div>

        {error ? (
          <div className="rounded-md border border-destructive/20 bg-destructive/10 px-3 py-2 text-destructive text-xs/relaxed">
            {error}
          </div>
        ) : null}

        {status === "loading" ? (
          <p className="text-muted-foreground text-xs/relaxed">
            Reading the custom event stream...
          </p>
        ) : null}

        {traceText ? (
          <div className="space-y-2">
            <p className="font-medium text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Reconstructed text
            </p>
            <div className="rounded-md bg-muted/50 px-3 py-3 text-sm/relaxed">
              {traceText}
            </div>
          </div>
        ) : null}

        {events.length > 0 ? (
          <Collapsible className="border border-foreground/10" defaultOpen={false}>
            <CollapsibleTrigger className="flex w-full items-center justify-between gap-4 px-3 py-2 text-left">
              <div className="space-y-1">
                <p className="font-medium text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
                  Parsed events
                </p>
                <p className="text-muted-foreground text-xs/relaxed">
                  Inspect the raw replay events only when you need the full
                  sequence.
                </p>
              </div>
              <CaretDownIcon className="size-4 text-muted-foreground transition-transform group-data-[state=open]:rotate-180" />
            </CollapsibleTrigger>

            <CollapsibleContent className="space-y-2 border-foreground/10 border-t px-3 py-3">
              {events.map((event, index) => (
                <div
                  className="rounded-md border border-foreground/10 px-3 py-2 text-xs/relaxed"
                  key={`${event.type}-${index}`}
                >
                  <div className="mb-1 flex items-center justify-between gap-3">
                    <span className="font-medium">{event.type}</span>
                    {event.type === "start" ? (
                      <Badge variant="outline">
                        {getAudienceLabel(event.audience)}
                      </Badge>
                    ) : null}
                  </div>
                  <pre className="overflow-x-auto whitespace-pre-wrap break-words text-muted-foreground">
                    {JSON.stringify(event, null, 2)}
                  </pre>
                </div>
              ))}
            </CollapsibleContent>
          </Collapsible>
        ) : null}
      </CollapsibleContent>
    </Collapsible>
  );
}

function StreamingDeveloperTrace({
  audience,
  chat,
}: StreamingDeveloperTraceProps) {
  const { messages } = useChat({ chat });
  const replayEntries = useMemo(() => getReplayPromptEntries(messages), [messages]);
  const latestEntry = replayEntries[0] ?? null;
  const historyEntries = replayEntries.slice(1);
  const hasMessages = messages.length > 0;

  return (
    <Collapsible className="border border-foreground/10" defaultOpen={false}>
      <CollapsibleTrigger className="flex w-full items-center justify-between gap-4 px-4 py-3 text-left">
        <div className="space-y-1">
          <p className="font-medium text-sm">Replayable developer trace</p>
          <p className="text-muted-foreground text-xs/relaxed">
            Replay assistant turns from the thread state that existed at each
            user prompt.
          </p>
        </div>
        <CaretDownIcon className="size-4 text-muted-foreground transition-transform group-data-[state=open]:rotate-180" />
      </CollapsibleTrigger>

      <CollapsibleContent className="space-y-4 border-foreground/10 border-t px-4 py-4">
        <div className="flex flex-wrap items-center gap-2">
          <Badge variant="outline">{getAudienceLabel(audience)}</Badge>
          <Badge variant="outline">{messages.length} thread messages</Badge>
          <Badge variant="outline">{replayEntries.length} user prompts</Badge>
        </div>

        {!hasMessages ? (
          <p className="text-muted-foreground text-xs/relaxed">
            Send a prompt to generate replayable prompt turns.
          </p>
        ) : null}

        {latestEntry ? (
          <div className="space-y-2">
            <p className="font-medium text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Correlated user prompt
            </p>
            <ReplayPromptCard
              audience={audience}
              defaultOpen
              entry={latestEntry}
              title="Correlated user prompt"
            />
          </div>
        ) : null}

        {historyEntries.length > 0 ? (
          <div className="space-y-2">
            <p className="font-medium text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              History prompt
            </p>
            <div className="space-y-3">
              {historyEntries.map((entry) => (
                <ReplayPromptCard
                  audience={audience}
                  entry={entry}
                  key={entry.id}
                  title="History prompt"
                />
              ))}
            </div>
          </div>
        ) : null}
      </CollapsibleContent>
    </Collapsible>
  );
}

export function StreamingChatShellWorkspace({
  chatModel,
  isChatAvailable,
  nodeVersion,
  setupMessage,
  supportedAudiences,
}: StreamingChatShellWorkspaceProps) {
  const normalizedAudiences = supportedAudiences as StreamingAudience[];
  const [audience, setAudience] = useState<StreamingAudience>(
    normalizedAudiences[0] ?? "engineers"
  );
  const [chat] = useState(
    () =>
      new Chat({
        transport: new DefaultChatTransport({
          api: "/api/demos/streaming-chat-shell",
        }),
      })
  );

  return (
    <div className="grid min-h-[70svh] gap-4 lg:grid-cols-[minmax(0,1fr)_20rem]">
      <section className="flex min-h-[70svh] flex-col border border-foreground/10 bg-background">
        <StreamingTranscript
          chat={chat}
          isChatAvailable={isChatAvailable}
          setupMessage={setupMessage}
        />
        <StreamingComposer
          audience={audience}
          chat={chat}
          chatModel={chatModel}
          isChatAvailable={isChatAvailable}
          onAudienceChange={setAudience}
          supportedAudiences={normalizedAudiences}
        />
      </section>

      <aside className="space-y-4">
        <section className="border border-foreground/10 bg-background p-4">
          <div className="space-y-4">
            <div>
              <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
                Runtime
              </p>
              <p className="mt-1 font-medium text-sm">{nodeVersion}</p>
            </div>
            <div>
              <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
                Request contract
              </p>
              <p className="mt-1 text-sm">
                Each request can carry feature-local metadata, while the main
                chat surface stays on the shared AI SDK transport contract.
              </p>
            </div>
            <div>
              <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
                Shared state
              </p>
              <p className="mt-1 text-sm">
                Transcript, composer, retry flow, and replay trace all read from
                the same `Chat` instance.
              </p>
            </div>
            <div>
              <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
                Developer value
              </p>
              <p className="mt-1 text-sm">
                The same conversation can be replayed as a plain SSE stream for
                debugging, inspection, and secondary developer tooling.
              </p>
            </div>
          </div>
        </section>

        <StreamingDeveloperTrace audience={audience} chat={chat} />
      </aside>
    </div>
  );
}

"use client";

import type { UIMessage } from "ai";
import { useMemo, useState } from "react";

import type { StreamingAudience } from "@/lib/streaming-chat-shell/contract";
import type { StreamingChatShellEvent } from "@/lib/streaming-chat-shell/streaming-turn";

const eventDelimiter = "\n\n";
const dataPrefix = "data:";

export interface ReplayPromptEntry {
  id: string;
  promptText: string;
  replayMessages: UIMessage[];
}

function getTextContent(message: UIMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n")
    .trim();
}

function parseEventChunk(chunk: string) {
  const dataLines = chunk
    .split("\n")
    .map((line) => line.trim())
    .filter((line) => line.startsWith(dataPrefix))
    .map((line) => line.slice(dataPrefix.length).trim());

  if (dataLines.length === 0) {
    return null;
  }

  return JSON.parse(dataLines.join("\n")) as StreamingChatShellEvent;
}

export function getReplayPromptEntries(messages: UIMessage[]) {
  const entries: ReplayPromptEntry[] = [];

  messages.forEach((message, index) => {
    if (message.role !== "user") {
      return;
    }

    const promptText = getTextContent(message);

    if (!promptText) {
      return;
    }

    entries.push({
      id: message.id,
      promptText,
      replayMessages: messages.slice(0, index + 1),
    });
  });

  return entries.reverse();
}

export function getReplayTraceText(events: StreamingChatShellEvent[]) {
  return events
    .filter(
      (event): event is Extract<StreamingChatShellEvent, { type: "text" }> =>
        event.type === "text"
    )
    .map((event) => event.text)
    .join("");
}

export function createStreamingReplayEventParser() {
  let buffer = "";

  return {
    push(chunk: string) {
      buffer += chunk;

      const events: StreamingChatShellEvent[] = [];

      while (true) {
        const delimiterIndex = buffer.indexOf(eventDelimiter);

        if (delimiterIndex === -1) {
          return events;
        }

        const rawChunk = buffer.slice(0, delimiterIndex);
        buffer = buffer.slice(delimiterIndex + eventDelimiter.length);

        const event = parseEventChunk(rawChunk);

        if (event) {
          events.push(event);
        }
      }
    },
  };
}

async function replayStreamingPromptTurn(
  audience: StreamingAudience,
  messages: UIMessage[]
) {
  const response = await fetch("/api/demos/streaming-chat-shell/events", {
    method: "POST",
    headers: {
      "content-type": "application/json",
    },
    body: JSON.stringify({
      audience,
      messages,
    }),
  });

  if (!response.ok) {
    let message = "Failed to replay the custom stream.";

    try {
      const payload = (await response.json()) as { error?: string };

      if (payload.error) {
        message = payload.error;
      }
    } catch {
      const fallbackText = await response.text();

      if (fallbackText) {
        message = fallbackText;
      }
    }

    throw new Error(message);
  }

  if (!response.body) {
    throw new Error("The custom event stream returned an empty body.");
  }

  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  const parser = createStreamingReplayEventParser();
  const replayEvents: StreamingChatShellEvent[] = [];

  while (true) {
    const { done, value } = await reader.read();

    if (done) {
      break;
    }

    const nextEvents = parser.push(decoder.decode(value, { stream: true }));

    if (nextEvents.length > 0) {
      replayEvents.push(...nextEvents);
    }
  }

  const trailingEvents = parser.push(decoder.decode());

  if (trailingEvents.length > 0) {
    replayEvents.push(...trailingEvents);
  }

  return replayEvents;
}

export function useStreamingReplayPrompt(
  audience: StreamingAudience,
  entry: ReplayPromptEntry
) {
  const [events, setEvents] = useState<StreamingChatShellEvent[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [status, setStatus] = useState<"idle" | "loading" | "ready" | "error">(
    "idle"
  );
  const traceText = useMemo(() => getReplayTraceText(events), [events]);
  const isReplayable = entry.replayMessages.length > 0;

  async function replayPrompt() {
    if (!isReplayable) {
      return;
    }

    setEvents([]);
    setError(null);
    setStatus("loading");

    try {
      const replayEvents = await replayStreamingPromptTurn(
        audience,
        entry.replayMessages
      );
      setEvents(replayEvents);
      setStatus("ready");
    } catch (replayError) {
      setError(
        replayError instanceof Error
          ? replayError.message
          : "Failed to replay the custom stream."
      );
      setStatus("error");
    }
  }

  return {
    error,
    events,
    isReplayable,
    status,
    traceText,
    replayPrompt,
  };
}

"use client";

import { CornerDownLeftIcon, LoaderCircleIcon, SquareIcon } from "lucide-react";
import type {
  ComponentProps,
  FormEvent,
  HTMLAttributes,
  ReactNode,
  TextareaHTMLAttributes,
} from "react";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

type PromptStatus = "error" | "ready" | "streaming" | "submitted";

interface PromptInputContextValue {
  setText: (text: string) => void;
  text: string;
}

interface PromptInputMessage {
  text: string;
}

interface PromptInputProps
  extends Omit<HTMLAttributes<HTMLFormElement>, "onSubmit"> {
  children: ReactNode;
  onSubmit: (
    message: PromptInputMessage,
    event: FormEvent<HTMLFormElement>
  ) => void | Promise<void>;
}

interface PromptInputSubmitProps
  extends Omit<ComponentProps<typeof Button>, "children" | "type"> {
  onStop?: () => void;
  status?: PromptStatus;
}

type PromptInputClickEvent = Parameters<
  Exclude<ComponentProps<typeof Button>["onClick"], undefined>
>[0];

const PromptInputContext = createContext<PromptInputContextValue | null>(null);

function usePromptInputContext() {
  const context = useContext(PromptInputContext);

  if (!context) {
    throw new Error(
      "PromptInput components must be used inside <PromptInput>."
    );
  }

  return context;
}

export function PromptInput({
  children,
  className,
  onSubmit,
  ...props
}: PromptInputProps) {
  const [text, setText] = useState("");

  const contextValue = useMemo(
    () => ({
      setText,
      text,
    }),
    [text]
  );

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      const nextText = text.trim();
      if (!nextText) {
        return;
      }

      const result = onSubmit({ text: nextText }, event);

      try {
        await result;
        setText("");
      } catch {
        // Keep the text for retry after a failed submit.
      }
    },
    [onSubmit, text]
  );

  return (
    <PromptInputContext.Provider value={contextValue}>
      <form
        className={cn("w-full", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </PromptInputContext.Provider>
  );
}

export function PromptInputBody({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("grid gap-3", className)} {...props} />;
}

export function PromptInputFooter({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn(className)} {...props} />;
}

export function PromptInputTextarea({
  className,
  disabled,
  onChange,
  ...props
}: TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const context = usePromptInputContext();

  return (
    <Textarea
      className={cn("min-h-16 resize-none", className)}
      disabled={disabled}
      onChange={(event) => {
        context.setText(event.currentTarget.value);
        onChange?.(event);
      }}
      value={context.text}
      {...props}
    />
  );
}

export function PromptInputSubmit({
  className,
  disabled,
  onClick,
  onStop,
  size = "icon",
  status = "ready",
  variant = "default",
  ...props
}: PromptInputSubmitProps) {
  const { text } = usePromptInputContext();
  const isBusy = status === "submitted" || status === "streaming";
  const isDisabled = Boolean(disabled) || (!isBusy && text.trim().length === 0);

  let icon = <CornerDownLeftIcon className="size-4" />;

  if (status === "submitted") {
    icon = <LoaderCircleIcon className="size-4 animate-spin" />;
  } else if (status === "streaming") {
    icon = <SquareIcon className="size-4" />;
  }

  return (
    <Button
      aria-label={isBusy ? "Stop" : "Submit"}
      className={cn(className)}
      disabled={isDisabled}
      onClick={(event: PromptInputClickEvent) => {
        if (isBusy && onStop) {
          event.preventDefault();
          onStop();
          return;
        }

        onClick?.(event);
      }}
      size={size}
      type={isBusy && onStop ? "button" : "submit"}
      variant={variant}
      {...props}
    >
      {icon}
    </Button>
  );
}

import { validateUIMessages, type UIMessage } from "ai";

export const invalidMessagesError =
  'Expected a JSON body with a "messages" array.';
export const invalidUiMessagesError =
  'Expected each "messages" entry to match the UIMessage format.';
export const malformedJsonError = "Expected a valid JSON request body.";
export const supportedAudiences = ["engineers", "buyers", "support"] as const;

export type StreamingAudience = (typeof supportedAudiences)[number];

interface StreamingChatShellRequestBody {
  audience?: string;
  messages?: UIMessage[];
}

export async function readStreamingChatShellRequest(body: unknown): Promise<{
  audience: StreamingAudience;
  messages: UIMessage[];
}> {
  const { audience, messages } = (body ?? {}) as StreamingChatShellRequestBody;

  if (!Array.isArray(messages)) {
    throw new Error(invalidMessagesError);
  }

  try {
    return {
      audience:
        supportedAudiences.find((candidate) => candidate === audience) ??
        "engineers",
      messages: await validateUIMessages({ messages }),
    };
  } catch {
    throw new Error(invalidUiMessagesError);
  }
}

import { createGateway } from "ai";
const DEFAULT_GATEWAY_BASE_URL = "https://ai-gateway.vercel.sh/v3/ai";
const DEFAULT_CHAT_MODEL = "openai/gpt-4.1-mini";
const MINIMUM_NODE_VERSION = "22.13.0";
const nodeVersionPattern = /^v?(\d+)\.(\d+)\.(\d+)(?:[-+].*)?$/;

interface ParsedNodeVersion {
  major: number;
  minor: number;
  patch: number;
}

export type StreamingChatShellEnv = Record<string, string | undefined>;

export interface StreamingChatShellConfig {
  apiKey: string;
  baseURL: string;
  chatModel: string;
}

export interface StreamingChatShellSetupState {
  config: Omit<StreamingChatShellConfig, "apiKey">;
  isReady: boolean;
  issues: string[];
  nodeVersion: string;
}

function parseNodeVersion(version: string): ParsedNodeVersion {
  const match = nodeVersionPattern.exec(version);
  const major = Number(match?.[1]);
  const minor = Number(match?.[2]);
  const patch = Number(match?.[3]);

  if (![major, minor, patch].every(Number.isInteger)) {
    throw new Error(`Unable to parse Node.js version: "${version}".`);
  }

  return { major, minor, patch };
}

function compareNodeVersions(
  left: ParsedNodeVersion,
  right: ParsedNodeVersion
) {
  if (left.major !== right.major) {
    return left.major - right.major;
  }

  if (left.minor !== right.minor) {
    return left.minor - right.minor;
  }

  return left.patch - right.patch;
}

function assertSupportedNodeRuntime(version = process.version) {
  const parsedVersion = parseNodeVersion(version);
  const minimumVersion = parseNodeVersion(MINIMUM_NODE_VERSION);

  if (compareNodeVersions(parsedVersion, minimumVersion) < 0) {
    throw new Error(
      `Node.js ${version} is unsupported. This demo workspace requires Node.js >=${MINIMUM_NODE_VERSION}.`
    );
  }
}

export function getStreamingChatShellEnv(): StreamingChatShellEnv {
  // biome-ignore lint/style/noProcessEnv: Registry source installs into consumer apps without this repo's env wrapper.
  return process.env;
}

function readRequiredEnv(
  env: StreamingChatShellEnv,
  name: keyof StreamingChatShellEnv
) {
  const value = env[name];

  if (!value) {
    throw new Error(
      `Missing ${name}. Add it to .env.local before using the streaming chat shell.`
    );
  }

  return value;
}

function resolveStreamingChatShellEnv(
  env: StreamingChatShellEnv = getStreamingChatShellEnv()
) {
  return {
    apiKey: env.AI_GATEWAY_API_KEY,
    baseURL: env.AI_GATEWAY_BASE_URL || DEFAULT_GATEWAY_BASE_URL,
    chatModel: env.AI_GATEWAY_CHAT_MODEL || DEFAULT_CHAT_MODEL,
  };
}

export function getStreamingChatShellConfig(
  env: StreamingChatShellEnv = getStreamingChatShellEnv()
): StreamingChatShellConfig {
  assertSupportedNodeRuntime();
  const resolvedEnv = resolveStreamingChatShellEnv(env);

  return {
    apiKey: readRequiredEnv(env, "AI_GATEWAY_API_KEY"),
    baseURL: resolvedEnv.baseURL,
    chatModel: resolvedEnv.chatModel,
  };
}

export function getStreamingChatShellSetupState(
  env: StreamingChatShellEnv = getStreamingChatShellEnv()
): StreamingChatShellSetupState {
  const issues: string[] = [];
  const resolvedEnv = resolveStreamingChatShellEnv(env);

  try {
    assertSupportedNodeRuntime();
  } catch (error) {
    issues.push(
      error instanceof Error ? error.message : "Unsupported Node.js runtime."
    );
  }

  if (!resolvedEnv.apiKey) {
    issues.push(
      "AI_GATEWAY_API_KEY is missing. The demo can render, but chat requests will fail until it is configured."
    );
  }

  return {
    config: {
      baseURL: resolvedEnv.baseURL,
      chatModel: resolvedEnv.chatModel,
    },
    isReady: issues.length === 0,
    issues,
    nodeVersion: process.version,
  };
}

export function createStreamingChatShellGateway(
  env: StreamingChatShellEnv = getStreamingChatShellEnv()
) {
  const { apiKey, baseURL } = getStreamingChatShellConfig(env);

  return createGateway({
    apiKey,
    baseURL,
  });
}

import type { UIMessage } from "ai";

import {
  invalidMessagesError,
  invalidUiMessagesError,
  malformedJsonError,
  readStreamingChatShellRequest,
  type StreamingAudience,
} from "./contract";
import {
  getStreamingChatShellEnv,
  getStreamingChatShellSetupState,
  type StreamingChatShellEnv,
} from "./env";
import {
  createStreamingTurnEventsResponse,
  type StreamingChatShellEvent,
  streamStreamingTurnEvents,
} from "./streaming-turn";

interface StreamingChatShellEventsDependencies {
  streamStreamingChatShellEvents: (
    messages: UIMessage[],
    env: StreamingChatShellEnv,
    options: { audience: StreamingAudience }
  ) => AsyncIterable<StreamingChatShellEvent>;
}

export async function* streamStreamingChatShellEvents(
  messages: UIMessage[],
  env: StreamingChatShellEnv,
  options: { audience: StreamingAudience }
): AsyncIterable<StreamingChatShellEvent> {
  yield* streamStreamingTurnEvents(messages, env, options.audience);
}

export async function handleStreamingChatShellEventsRequest(
  request: Request,
  env: StreamingChatShellEnv = getStreamingChatShellEnv(),
  dependencies: StreamingChatShellEventsDependencies = {
    streamStreamingChatShellEvents,
  }
) {
  const runtimeState = getStreamingChatShellSetupState(env);

  if (!runtimeState.isReady) {
    return Response.json(
      {
        error:
          runtimeState.issues.length > 0
            ? runtimeState.issues.join(" ")
            : "AI Gateway setup is required.",
      },
      { status: 500 }
    );
  }

  try {
    const { audience, messages } = await readStreamingChatShellRequest(
      await request.json()
    );
    if (
      dependencies.streamStreamingChatShellEvents ===
      streamStreamingChatShellEvents
    ) {
      return createStreamingTurnEventsResponse(messages, env, audience);
    }

    const encoder = new TextEncoder();
    const eventStream = await dependencies.streamStreamingChatShellEvents(
      messages,
      env,
      {
        audience,
      }
    );

    return new Response(
      new ReadableStream({
        async start(controller) {
          for await (const event of eventStream) {
            controller.enqueue(
              encoder.encode(`data: ${JSON.stringify(event)}\n\n`)
            );
          }

          controller.close();
        },
      }),
      {
        headers: {
          "cache-control": "no-cache",
          "content-type": "text/event-stream; charset=utf-8",
        },
      }
    );
  } catch (error) {
    if (error instanceof SyntaxError) {
      return Response.json(
        {
          error: malformedJsonError,
        },
        { status: 400 }
      );
    }

    if (
      error instanceof Error &&
      [invalidMessagesError, invalidUiMessagesError].includes(error.message)
    ) {
      return Response.json(
        {
          error: error.message,
        },
        { status: 400 }
      );
    }

    throw error;
  }
}

